body:
[AndOfPadS](https://github.com/llvm/circt/blob/08b407136823ad8516e16674abdb297688cf5206/include/circt/Dialect/FIRRTL/FIRRTLCanonicalization.td#L311-L315) will always keep the most significant bit of the unpadded operand, but the padded operand may be sign-extended with either zeros or ones.
```mlir
firrtl.circuit "ConstInput" {
  firrtl.module @ConstInput(out %out: !firrtl.uint<3>) {
    %x = firrtl.constant -1 : !firrtl.sint<3>
    %y = firrtl.constant 1 : !firrtl.sint<2>
    %i_x, %i_y, %i_out = firrtl.instance i @AndOfPadS(in x: !firrtl.sint<3>, in y: !firrtl.sint<2>, out out: !firrtl.uint<3>)
    firrtl.connect %i_x, %x : !firrtl.sint<3>, !firrtl.sint<3>
    firrtl.connect %i_y, %y : !firrtl.sint<2>, !firrtl.sint<2>
    firrtl.connect %out, %i_out : !firrtl.uint<3>, !firrtl.uint<3>
  }

  firrtl.module private @AndOfPadS(in %x: !firrtl.sint<3>, in %y: !firrtl.sint<2>, out %out: !firrtl.uint<3>) {
    %pad = firrtl.pad %y, 3 : (!firrtl.sint<2>) -> !firrtl.sint<3>
    %and = firrtl.and %x, %pad : (!firrtl.sint<3>, !firrtl.sint<3>) -> !firrtl.uint<3>
    firrtl.strictconnect %out, %and : !firrtl.uint<3>
  }
}
```

running `circt-opt -pass-pipeline='builtin.module(firrtl.circuit(firrtl-imconstprop))' %s` outputs
```mlir
module {
  firrtl.circuit "ConstInput" {
    firrtl.module @ConstInput(out %out: !firrtl.uint<3>) {
      %c1_ui3 = firrtl.constant 1 : !firrtl.uint<3>
      %c-1_si3 = firrtl.constant -1 : !firrtl.sint<3>
      %c1_si2 = firrtl.constant 1 : !firrtl.sint<2>
      %i_x, %i_y, %i_out = firrtl.instance i @AndOfPadS(in x: !firrtl.sint<3>, in y: !firrtl.sint<2>, out out: !firrtl.uint<3>)
      firrtl.connect %i_x, %c-1_si3 : !firrtl.sint<3>, !firrtl.sint<3>
      firrtl.connect %i_y, %c1_si2 : !firrtl.sint<2>, !firrtl.sint<2>
      firrtl.connect %out, %c1_ui3 : !firrtl.uint<3>, !firrtl.uint<3>
    }
    firrtl.module private @AndOfPadS(in %x: !firrtl.sint<3>, in %y: !firrtl.sint<2>, out %out: !firrtl.uint<3>) {
      %c1_ui3 = firrtl.constant 1 : !firrtl.uint<3>
      firrtl.strictconnect %out, %c1_ui3 : !firrtl.uint<3>
    }
  }
}
```

while running `circt-opt -pass-pipeline='builtin.module(canonicalize{top-down region-simplify}, firrtl.circuit(firrtl-imconstprop))' %s` outputs
```mlir
module {
  firrtl.circuit "ConstInput" {
    firrtl.module @ConstInput(out %out: !firrtl.uint<3>) {
      %c5_ui3 = firrtl.constant 5 : !firrtl.uint<3>
      %c-1_si3 = firrtl.constant -1 : !firrtl.sint<3>
      %c1_si2 = firrtl.constant 1 : !firrtl.sint<2>
      %i_x, %i_y, %i_out = firrtl.instance i @AndOfPadS(in x: !firrtl.sint<3>, in y: !firrtl.sint<2>, out out: !firrtl.uint<3>)
      firrtl.strictconnect %i_x, %c-1_si3 : !firrtl.sint<3>
      firrtl.strictconnect %i_y, %c1_si2 : !firrtl.sint<2>
      firrtl.strictconnect %out, %c5_ui3 : !firrtl.uint<3>
    }
    firrtl.module private @AndOfPadS(in %x: !firrtl.sint<3>, in %y: !firrtl.sint<2>, out %out: !firrtl.uint<3>) {
      %c5_ui3 = firrtl.constant 5 : !firrtl.uint<3>
      firrtl.strictconnect %out, %c5_ui3 : !firrtl.uint<3>
    }
  }
}
```

I expect the `out` to be constant propagated to 1 instead of 5.
